"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[492],{460:e=>{e.exports=JSON.parse('{"functions":[{"name":"cast","desc":"Fires a projectile. Resolves `options.type` against the definitions module,\\nthen dispatches to the least-loaded simulation actor in the pool.\\n\\nOn the server, `timestamp` should reflect the moment from the shooter\'s\\nperspective \u2014 typically `clientTimestamp - playerPing - interpolation`.\\nOn the client, `workspace:GetServerTimeNow()` is fine \u2014 the client World\\nhas no rollback path.","params":[{"name":"options","desc":"","lua_type":"CastOptions"}],"returns":[],"function_type":"method","source":{"line":461,"path":"src/World.lua"}},{"name":"destroy","desc":"Tears down the simulation actor pool. Disconnects every Output binding,\\ndestroys every Actor, and clears internal references. After `destroy`, the\\nWorld is unusable \u2014 build a new one with [`Hindsight.createWorld`](Hindsight#createWorld).","params":[],"returns":[],"function_type":"method","source":{"line":473,"path":"src/World.lua"}}],"properties":[{"name":"rollback","desc":"The rollback store. See the [`Rollback`](Rollback) class for the full\\nmethod list.","lua_type":"Rollback","source":{"line":62,"path":"src/World.lua"}}],"types":[],"name":"World","desc":"A simulation world. Owns the actor pool, the snapshot store, and the\\nprojectile definitions registry. Built by [`Hindsight.createWorld`](Hindsight#createWorld).\\n\\nA typical server uses one World; clients use one World per peer for\\nvisuals only. Server and client Worlds do not share state \u2014 both speak the\\nsame definitions module independently because each Actor `require`s the\\nmodule in its own VM.","source":{"line":34,"path":"src/World.lua"}}')}}]);